#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        double *res = (double*)malloc(N * sizeof(double));
        for (int i = 0; i < N; ++i) {
            int inch;
            scanf("%d", &inch);
            res[i] = inch * 2.54;
        }
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%.1f", res[i]);
        }
        printf("\n");
        free(res);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> a(N);
        for (int &x : a) cin >> x;
        vector<double> cm(N);
        transform(a.begin(), a.end(), cm.begin(), [](int x){ return x * 2.54; });
        cout.setf(ios::fixed);
        cout << setprecision(1);
        for (int i = 0; i < N; ++i) {
            if (i) cout << ' ';
            cout << cm[i];
        }
        if (T) cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] arr = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) arr[i] = Integer.parseInt(st.nextToken());
            for (int i = 0; i < N; i++) {
                double cm = arr[i] * 2.54;
                out.append(String.format(java.util.Locale.US, "%.1f", cm));
                if (i + 1 < N) out.append(' ');
            }
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

