const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const inches = [];
  for (let i = 0; i < N; i++) inches.push(Number(input[idx++]));
  const cm = inches.map(x => x * 2.54);
  outputs.push(cm.map(v => v.toFixed(1)).join(' '));
}
console.log(outputs.join('\n'));

